import React, { useEffect, useRef } from 'react';
import profileImage from '../assets/profile.png';
import silhouette1 from '../assets/silhouette1.png';
import silhouette2 from '../assets/silhouette2.png';
import '../styles/components/About.css';

const About = () => {
  const sectionRef = useRef(null);
  const [isVisible, setIsVisible] = React.useState(false);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
        }
      },
      { threshold: 0.1 }
    );

    if (sectionRef.current) {
      observer.observe(sectionRef.current);
    }

    return () => {
      if (sectionRef.current) {
        observer.unobserve(sectionRef.current);
      }
    };
  }, []);

  return (
    <section id="about" className="about section" ref={sectionRef}>
      <img src={silhouette1} alt="" className="section-silhouette section-silhouette-1" />
      <img src={silhouette2} alt="" className="section-silhouette section-silhouette-2" />
      <div className="container">
        <h2 className="section-title">About Me</h2>
        <div className={`about-content ${isVisible ? 'visible' : ''}`}>
          <div className="about-image-wrapper">
            <div className="image-border"></div>
            <img 
              src={profileImage} 
              alt="Aarav Sahni in aircraft cockpit" 
              className="about-image"
            />
            <div className="image-glow"></div>
          </div>
          <div className="about-text">
            <p>
              I'm Aarav, a student who's deeply into technology, engineering, and aviation, and I'm driven by a need to understand how complex systems actually work under the hood. I don't just use tools or software—I break them apart mentally, rebuild them, and question every assumption until the logic is solid. I run my own servers and infrastructure, including self-hosted services, Docker containers, game servers, custom domains, and automation tools, and I'm comfortable working in Linux, reading logs, debugging failures, and configuring systems properly rather than relying on trial and error. When something goes wrong, I want the root cause, not a surface-level fix.
            </p>
            <p>
              At the same time, I'm deliberately building strong foundations in software development and engineering. I'm learning backend development with TypeScript and Python, alongside lower-level concepts like memory management in C, because I want to understand what abstractions are hiding and why systems behave the way they do. I prefer doing the work myself—even when it's slower or more frustrating—because that's how real understanding forms. I value blunt, no-nonsense feedback that exposes weak thinking so I can correct it and improve. Alongside software, I'm a maker: I work with Raspberry Pi and microcontrollers, sensors, displays, electronics, and 3D printing, and I naturally think of hardware and software as parts of one integrated system.
            </p>
            <p>
              Aviation is a major part of who I am. I'm deeply into flight simulation and real-world aviation procedures, flying realistically and studying how aircraft systems, navigation, and operations work in practice. I care about realism, accuracy, and discipline, whether that's following proper procedures in a simulated cockpit or building physical and digital setups that mirror real aircraft behavior. Overall, I'm curious, detail-oriented, and obsessive in a productive way—I want deep understanding, not shortcuts, and I'm constantly pushing myself to turn interest into genuine skill.
            </p>
          </div>
        </div>
      </div>
    </section>
  );
};

export default About;
